            <form
              onSubmit={handleAddMetric}
              className="bg-cream rounded-[2rem] p-5 shadow-[0_1px_3px_rgba(0,0,0,0.05)] flex flex-col gap-3"
            >
              <h3 className="text-[10px] tracking-[0.15em] uppercase text-forest font-medium mb-2">
                New Metric
              </h3>
              <input
